1	interface CustomerContext {
2	  yearsWithMHPCO: number;
3	  previousQuotes: number;
4	}
5	
6	interface Item {
7	  type: string;
8	  cursed?: boolean;
9	  enchantment?: number;
10	}
11	
12	const BASE_PREMIUM: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const PROCESSING_FEE = 5;
22	
23	const COMPONENT_TYPES = ["rune", "moonstone"];
24	const BLOCK_SIZE = 3;
25	const BLOCK_PREMIUM = 60;
26	
27	const LOYALTY_YEARS_THRESHOLD = 2;
28	const LOYALTY_DISCOUNT_RATE = 0.2;
29	
30	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
31	
32	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
33	
34	function countByType(items: Item[]): Record<string, number> {
35	  const counts: Record<string, number> = {};
36	  for (const item of items) {
37	    counts[item.type] = (counts[item.type] ?? 0) + 1;
38	  }
39	  return counts;
40	}
41	
42	function basePremiumForType(type: string): number {
43	  return BASE_PREMIUM[type] ?? 0;
44	}
45	
46	function cursedSurchargeFor(item: Item): number {
47	  return item.cursed ? basePremiumForType(item.type) * 0.5 : 0;
48	}
49	
50	function highEnchantmentSurchargeFor(item: Item): number {
51	  return (item.enchantment ?? 0) >= 5 ? basePremiumForType(item.type) * 0.3 : 0;
52	}
53	
54	function itemSurchargesFor(item: Item): number {
55	  return cursedSurchargeFor(item) + highEnchantmentSurchargeFor(item);
56	}
57	
58	function loyaltyDiscountFor(basePremium: number, customer: CustomerContext): number {
59	  return customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
60	    ? basePremium * LOYALTY_DISCOUNT_RATE
61	    : 0;
62	}
63	
64	function firstInsuranceSurchargeFor(basePremium: number): number {
65	  return basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
66	}
67	
68	function followUpDiscountFor(basePremium: number, customer: CustomerContext): number {
69	  return customer.previousQuotes >= 1
70	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
71	    : 0;
72	}
73	
74	function premiumForGroup(type: string, count: number): number {
75	  if (COMPONENT_TYPES.includes(type) && count === BLOCK_SIZE) {
76	    return BLOCK_PREMIUM;
77	  }
78	  return count * basePremiumForType(type);
79	}
80	
81	export function quote(items: Item[], customer: CustomerContext): number {
82	  const counts = countByType(items);
83	
84	  const basePremium = Object.entries(counts)
85	    .reduce((sum, [type, count]) => sum + premiumForGroup(type, count), 0);
86	
87	  const itemSurcharges = items.reduce((sum, item) =>
88	    sum + itemSurchargesFor(item), 0);
89	
90	  const policyAdjustment =
91	    - loyaltyDiscountFor(basePremium, customer)
92	    + firstInsuranceSurchargeFor(basePremium)
93	    - followUpDiscountFor(basePremium, customer);
94	
95	  return Math.ceil(basePremium + itemSurcharges + policyAdjustment + PROCESSING_FEE);
96	}
